// create one item per backup target and attach folderId
const folderId = $node["Create Backup Folder"].json["id"];
const backups = $node["Set Default Backup Config"].json["backups"];
return backups.map(b => ({ json: { ...b, folderId } }));

const zlib = require('zlib');
return $input.all().map(item => {
  const binKey = Object.keys(item.binary)[0];
  const compressed = zlib.gzipSync(Buffer.from(item.binary[binKey].data, 'base64'));
  return {
    json: {
      name: item.json.name,
      folderId: item.json.folderId
    },
    binary: {
      data: {
        data: compressed.toString('base64'),
        mimeType: 'application/gzip',
        fileName: `${item.json.name}-${new Date().toISOString()}.gz`
      }
    }
  };
});
